                ["NewSessionApprovalHelp"] = "\u0417\u0434\u0435\u0441\u044c \u0432\u044b\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044f, \u043a\u043e\u0433\u0434\u0430 Codex \u0434\u043e\u043b\u0436\u0435\u043d \u0441\u043f\u0440\u0430\u0448\u0438\u0432\u0430\u0442\u044c \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u0435 \u043f\u0435\u0440\u0435\u0434 \u0437\u0430\u043f\u0443\u0441\u043a\u043e\u043c \u043a\u043e\u043c\u0430\u043d\u0434.",
                ["NewSessionApprovalOnRequest"] = "\u0421\u043f\u0440\u0430\u0448\u0438\u0432\u0430\u0442\u044c \u043f\u0440\u0438 \u043d\u0435\u043e\u0431\u0445\u043e\u0434\u0438\u043c\u043e\u0441\u0442\u0438",
                ["NewSessionApprovalOnRequestHelp"] = "\u0421\u0431\u0430\u043b\u0430\u043d\u0441\u0438\u0440\u043e\u0432\u0430\u043d\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442. Codex \u0441\u0430\u043c \u0440\u0435\u0448\u0430\u0435\u0442, \u043a\u043e\u0433\u0434\u0430 \u043d\u0443\u0436\u043d\u043e \u0441\u043f\u0440\u043e\u0441\u0438\u0442\u044c \u043f\u043e\u0434\u0442\u0432\u0435\u0440\u0436\u0434\u0435\u043d\u0438\u0435.",
                ["NewSessionApprovalNever"] = "\u041d\u0438\u043a\u043e\u0433\u0434\u0430 \u043d\u0435 \u0441\u043f\u0440\u0430\u0448\u0438\u0432\u0430\u0442\u044c",
                ["NewSessionApprovalNeverHelp"] = "\u0412\u0441\u0435 \u043a\u043e\u043c\u0430\u043d\u0434\u044b \u0431\u0443\u0434\u0443\u0442 \u0438\u0434\u0442\u0438 \u0431\u0435\u0437 \u0434\u043e\u043f\u043e\u043b\u043d\u0438\u0442\u0435\u043b\u044c\u043d\u044b\u0445 \u0432\u043e\u043f\u0440\u043e\u0441\u043e\u0432.",
                ["NewSessionApprovalUntrusted"] = "\u0421\u043f\u0440\u0430\u0448\u0438\u0432\u0430\u0442\u044c \u0434\u043b\u044f \u0440\u0438\u0441\u043a\u043e\u0432\u044b\u0445 \u043a\u043e\u043c\u0430\u043d\u0434",
                ["NewSessionApprovalUntrustedHelp"] = "\u0423\u0434\u043e\u0431\u043d\u044b\u0439 \u0438 \u0431\u043e\u043b\u0435\u0435 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u044b\u0439 \u0432\u0430\u0440\u0438\u0430\u043d\u0442 \u0434\u043b\u044f \u043d\u043e\u0432\u0438\u0447\u043a\u043e\u0432: \u043e\u0431\u044b\u0447\u043d\u044b\u0435 \u043a\u043e\u043c\u0430\u043d\u0434\u044b \u0438\u0434\u0443\u0442 \u0441\u0440\u0430\u0437\u0443, \u0440\u0438\u0441\u043a\u043e\u0432\u044b\u0435 \u0441 \u0432\u043e\u043f\u0440\u043e\u0441\u043e\u043c.",
                ["NewSessionLocalProviderHelp"] = "\u042d\u0442\u043e \u043f\u043e\u043b\u0435 \u0438\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0435\u0442\u0441\u044f \u0442\u043e\u043b\u044c\u043a\u043e \u043f\u0440\u0438 \u0432\u043a\u043b\u044e\u0447\u0435\u043d\u043d\u043e\u043c \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u043c OSS-\u0440\u0435\u0436\u0438\u043c\u0435. \u0417\u0434\u0435\u0441\u044c \u0432\u044b\u0431\u0438\u0440\u0430\u0435\u0442\u0441\u044f, \u043a \u043a\u0430\u043a\u043e\u043c\u0443 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u043c\u0443 \u0441\u0435\u0440\u0432\u0435\u0440\u0443 \u043c\u043e\u0434\u0435\u043b\u0435\u0439 \u0431\u0443\u0434\u0435\u0442 \u043f\u043e\u0434\u043a\u043b\u044e\u0447\u0430\u0442\u044c\u0441\u044f Codex.",
                ["NewSessionLocalProviderNone"] = "\u0418\u0437 config / \u043d\u0435 \u0437\u0430\u0434\u0430\u043d",
                ["NewSessionLocalProviderNoneHelp"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 provider \u0438\u0437 Codex config \u0438\u043b\u0438 \u043e\u0441\u0442\u0430\u0432\u044c\u0442\u0435 \u043e\u0431\u044b\u0447\u043d\u044b\u0439 cloud-\u0440\u0435\u0436\u0438\u043c.",
                ["NewSessionLocalProviderLmStudioHelp"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 LM Studio \u043a\u0430\u043a \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u0441\u0435\u0440\u0432\u0435\u0440 \u0434\u043b\u044f open-source \u043c\u043e\u0434\u0435\u043b\u0435\u0439.",
                ["NewSessionLocalProviderOllamaHelp"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 Ollama \u043a\u0430\u043a \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u0441\u0435\u0440\u0432\u0435\u0440 \u0434\u043b\u044f open-source \u043c\u043e\u0434\u0435\u043b\u0435\u0439.",
                ["NewSessionFlagsHelp"] = "Search включает web-поиск, а OSS переключает Codex на локального провайдера моделей.",
                ["NewSessionPreviewHelp"] = "\u0417\u0434\u0435\u0441\u044c \u043f\u043e\u043a\u0430\u0437\u0430\u043d\u0430 \u0442\u043e\u0447\u043d\u0430\u044f \u0438\u043d\u0442\u0435\u0440\u0430\u043a\u0442\u0438\u0432\u043d\u0430\u044f \u043a\u043e\u043c\u0430\u043d\u0434\u0430 Codex, \u043a\u043e\u0442\u043e\u0440\u0443\u044e AIHelper \u043e\u0442\u043f\u0440\u0430\u0432\u0438\u0442 \u0432 \u043d\u043e\u0432\u043e\u0435 \u043e\u043a\u043d\u043e \u0442\u0435\u0440\u043c\u0438\u043d\u0430\u043b\u0430.",
                ["NewSessionBeginnerTitle"] = "\u0411\u044b\u0441\u0442\u0440\u044b\u0439 \u0441\u0442\u0430\u0440\u0442 \u0434\u043b\u044f \u043d\u043e\u0432\u0438\u0447\u043a\u0430",
                ["NewSessionBeginnerText"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u0443\u0439\u0442\u0435 \u0433\u043e\u0442\u043e\u0432\u044b\u0435 \u043f\u0440\u0438\u043c\u0435\u0440\u044b \u043d\u0438\u0436\u0435, \u0435\u0441\u043b\u0438 \u0445\u043e\u0442\u0438\u0442\u0435 \u0431\u044b\u0441\u0442\u0440\u043e \u0441\u0442\u0430\u0440\u0442\u043e\u0432\u0430\u0442\u044c \u0431\u0435\u0437 \u0440\u0443\u0447\u043d\u043e\u0439 \u0441\u0431\u043e\u0440\u043a\u0438 prompt.",
                ["NewSessionPresetCloudButton"] = "\u041f\u043e\u0441\u0442\u0430\u0432\u0438\u0442\u044c \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u0439 \u043f\u0440\u0435\u0441\u0435\u0442 Codex",
                ["NewSessionPresetLocalButton"] = "\u041f\u043e\u0441\u0442\u0430\u0432\u0438\u0442\u044c \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u043f\u0440\u0435\u0441\u0435\u0442 Ollama",
                ["NewSessionPresetCloudApplied"] = "\u0412 \u0444\u043e\u0440\u043c\u0443 \u043d\u043e\u0432\u043e\u0439 \u0441\u0435\u0441\u0441\u0438\u0438 \u043f\u043e\u0434\u0441\u0442\u0430\u0432\u043b\u0435\u043d \u0441\u0442\u0430\u043d\u0434\u0430\u0440\u0442\u043d\u044b\u0439 \u043f\u0440\u0435\u0441\u0435\u0442 Codex.",
                ["NewSessionPresetLocalApplied"] = "\u0412 \u0444\u043e\u0440\u043c\u0443 \u043d\u043e\u0432\u043e\u0439 \u0441\u0435\u0441\u0441\u0438\u0438 \u043f\u043e\u0434\u0441\u0442\u0430\u0432\u043b\u0435\u043d \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u043f\u0440\u0435\u0441\u0435\u0442 Ollama.",
                ["NewSessionExampleProjectTitle"] = "\u0420\u0430\u0437\u043e\u0431\u0440\u0430\u0442\u044c \u043f\u0440\u043e\u0435\u043a\u0442",
                ["NewSessionExampleProjectText"] = "\u0411\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u044b\u0439 cloud-\u0441\u0446\u0435\u043d\u0430\u0440\u0438\u0439, \u0447\u0442\u043e\u0431\u044b \u043f\u043e\u043d\u044f\u0442\u044c \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0443 \u043a\u043e\u0434\u0430, \u043a\u043b\u044e\u0447\u0435\u0432\u044b\u0435 \u0444\u0430\u0439\u043b\u044b \u0438 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0438\u0435 \u0448\u0430\u0433\u0438 \u043f\u043e \u0440\u0430\u0437\u0440\u0430\u0431\u043e\u0442\u043a\u0435.",
                ["NewSessionExampleProjectButton"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c \u043f\u0440\u0438\u043c\u0435\u0440 \u0440\u0430\u0437\u0431\u043e\u0440\u0430 \u043f\u0440\u043e\u0435\u043a\u0442\u0430",
                ["NewSessionExampleProjectPrompt"] = "\u0418\u0437\u0443\u0447\u0438 \u044d\u0442\u043e\u0442 \u043f\u0440\u043e\u0435\u043a\u0442, \u043a\u0440\u0430\u0442\u043a\u043e \u043e\u043f\u0438\u0448\u0438 \u0435\u0433\u043e \u0441\u0442\u0440\u0443\u043a\u0442\u0443\u0440\u0443, \u043d\u0430\u0439\u0434\u0438 \u0442\u043e\u0447\u043a\u0438 \u0432\u0445\u043e\u0434\u0430 \u0438 \u043e\u0441\u043d\u043e\u0432\u043d\u044b\u0435 \u043c\u043e\u0434\u0443\u043b\u0438, \u0430 \u043f\u043e\u0442\u043e\u043c \u043f\u0440\u0435\u0434\u043b\u043e\u0436\u0438 \u043f\u0440\u0430\u043a\u0442\u0438\u0447\u043d\u044b\u0435 \u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0438\u0435 \u0448\u0430\u0433\u0438.",
                ["NewSessionExampleProjectApplied"] = "\u0412 \u0444\u043e\u0440\u043c\u0443 \u043d\u043e\u0432\u043e\u0439 \u0441\u0435\u0441\u0441\u0438\u0438 \u043f\u043e\u0434\u0441\u0442\u0430\u0432\u043b\u0435\u043d \u043f\u0440\u0438\u043c\u0435\u0440 \u0440\u0430\u0437\u0431\u043e\u0440\u0430 \u043f\u0440\u043e\u0435\u043a\u0442\u0430.",
                ["NewSessionExampleBugfixTitle"] = "\u041d\u0430\u0439\u0442\u0438 \u0438 \u0438\u0441\u043f\u0440\u0430\u0432\u0438\u0442\u044c \u0431\u0430\u0433",
                ["NewSessionExampleBugfixText"] = "\u0421\u0446\u0435\u043d\u0430\u0440\u0438\u0439 \u0434\u043b\u044f \u043f\u043e\u0438\u0441\u043a\u0430 \u043f\u0440\u0438\u0447\u0438\u043d\u044b \u043f\u0440\u043e\u0431\u043b\u0435\u043c\u044b, \u043c\u0438\u043d\u0438\u043c\u0430\u043b\u044c\u043d\u043e\u0439 \u043f\u0440\u0430\u0432\u043a\u0438 \u0438 \u043f\u043e\u0441\u043b\u0435\u0434\u0443\u044e\u0449\u0435\u0439 \u043f\u0440\u043e\u0432\u0435\u0440\u043a\u0438.",
                ["NewSessionExampleBugfixButton"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c \u043f\u0440\u0438\u043c\u0435\u0440 \u0434\u043b\u044f \u0431\u0430\u0433\u0444\u0438\u043a\u0441\u0430",
                ["NewSessionExampleBugfixPrompt"] = "\u041d\u0430\u0439\u0434\u0438 \u043f\u0440\u0438\u0447\u0438\u043d\u0443 \u0442\u0435\u043a\u0443\u0449\u0435\u0439 \u043e\u0448\u0438\u0431\u043a\u0438 \u0432 \u044d\u0442\u043e\u043c \u043f\u0440\u043e\u0435\u043a\u0442\u0435, \u043a\u0440\u0430\u0442\u043a\u043e \u043e\u0431\u044a\u044f\u0441\u043d\u0438 \u0435\u0451 \u0438\u0441\u0442\u043e\u0447\u043d\u0438\u043a, \u0432\u043d\u0435\u0441\u0438 \u043c\u0438\u043d\u0438\u043c\u0430\u043b\u044c\u043d\u0443\u044e \u043d\u0430\u0434\u0451\u0436\u043d\u0443\u044e \u043f\u0440\u0430\u0432\u043a\u0443 \u0438 \u043f\u043e\u0442\u043e\u043c \u043f\u0440\u043e\u0432\u0435\u0440\u044c \u0440\u0435\u0437\u0443\u043b\u044c\u0442\u0430\u0442.",
                ["NewSessionExampleBugfixApplied"] = "\u0412 \u0444\u043e\u0440\u043c\u0443 \u043d\u043e\u0432\u043e\u0439 \u0441\u0435\u0441\u0441\u0438\u0438 \u043f\u043e\u0434\u0441\u0442\u0430\u0432\u043b\u0435\u043d \u043f\u0440\u0438\u043c\u0435\u0440 \u0434\u043b\u044f \u0431\u0430\u0433\u0444\u0438\u043a\u0441\u0430.",
                ["NewSessionExampleLocalTitle"] = "\u0420\u0430\u0431\u043e\u0442\u0430 \u0441 \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u043e\u0439 \u043c\u043e\u0434\u0435\u043b\u044c\u044e",
                ["NewSessionExampleLocalText"] = "\u041b\u043e\u043a\u0430\u043b\u044c\u043d\u0430\u044f OSS-\u0441\u0435\u0441\u0441\u0438\u044f \u0447\u0435\u0440\u0435\u0437 Ollama \u0434\u043b\u044f \u043a\u043e\u0440\u043e\u0442\u043a\u0438\u0445 offline-\u0437\u0430\u0434\u0430\u0447, \u043f\u0440\u043e\u0441\u0442\u044b\u0445 \u043f\u0440\u0430\u0432\u043e\u043a \u0438 \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u043e\u0432.",
                ["NewSessionExampleLocalButton"] = "\u0418\u0441\u043f\u043e\u043b\u044c\u0437\u043e\u0432\u0430\u0442\u044c \u043f\u0440\u0438\u043c\u0435\u0440 \u0441 Ollama",
                ["NewSessionExampleLocalPrompt"] = "\u0420\u0430\u0431\u043e\u0442\u0430\u0439 \u043a\u0430\u043a \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 coding assistant \u0434\u043b\u044f \u044d\u0442\u043e\u0439 \u043f\u0430\u043f\u043a\u0438: \u0438\u0437\u0443\u0447\u0438 \u0444\u0430\u0439\u043b\u044b, \u043e\u0442\u0432\u0435\u0447\u0430\u0439 \u043a\u0440\u0430\u0442\u043a\u043e \u0438 \u0434\u0435\u043b\u0430\u0439 \u0442\u043e\u043b\u044c\u043a\u043e \u043d\u0435\u0431\u043e\u043b\u044c\u0448\u0438\u0435 \u0431\u0435\u0437\u043e\u043f\u0430\u0441\u043d\u044b\u0435 \u0438\u0437\u043c\u0435\u043d\u0435\u043d\u0438\u044f, \u043a\u043e\u0433\u0434\u0430 \u043e\u043d\u0438 \u044f\u0432\u043d\u043e \u043d\u0443\u0436\u043d\u044b.",
                ["NewSessionExampleLocalApplied"] = "\u0412 \u0444\u043e\u0440\u043c\u0443 \u043d\u043e\u0432\u043e\u0439 \u0441\u0435\u0441\u0441\u0438\u0438 \u043f\u043e\u0434\u0441\u0442\u0430\u0432\u043b\u0435\u043d \u043b\u043e\u043a\u0430\u043b\u044c\u043d\u044b\u0439 \u043f\u0440\u0438\u043c\u0435\u0440 \u0441 Ollama.",
                ["SetupTitle"] = "\u0423\u0441\u0442\u0430\u043d\u043e\u0432\u043a\u0430 Codex",
                ["SetupSubtitle"] = "Проверьте локальное окружение и устанавливайте нативное приложение Codex, Codex CLI и локальные AI-инструменты.",
                ["SetupStartHereTitle"] = "\u0421 \u0447\u0435\u0433\u043e \u043d\u0430\u0447\u0430\u0442\u044c \u043d\u043e\u0432\u0438\u0447\u043a\u0443",
