                ["SettingsPhotoPasteFixWarningMessage"] = "\u042d\u0442\u043e \u044d\u043a\u0441\u043f\u0435\u0440\u0438\u043c\u0435\u043d\u0442\u0430\u043b\u044c\u043d\u0430\u044f \u0444\u0443\u043d\u043a\u0446\u0438\u044f, \u0438 \u043f\u043e\u043a\u0430 \u043d\u0435 \u0440\u0435\u043a\u043e\u043c\u0435\u043d\u0434\u0443\u0435\u0442\u0441\u044f \u0434\u0435\u0440\u0436\u0430\u0442\u044c \u0435\u0451 \u0432\u043a\u043b\u044e\u0447\u0451\u043d\u043d\u043e\u0439 \u0434\u043b\u044f \u043e\u0431\u044b\u0447\u043d\u043e\u0439 \u0440\u0430\u0431\u043e\u0442\u044b.\n\nAIHelper \u0431\u0443\u0434\u0435\u0442 \u043f\u0435\u0440\u0435\u0445\u0432\u0430\u0442\u044b\u0432\u0430\u0442\u044c Alt+V \u0438 Ctrl+V \u0442\u043e\u043b\u044c\u043a\u043e \u0432 \u043e\u043a\u043d\u0430\u0445 AIHelper Codex.\n\n\u0415\u0441\u043b\u0438 \u0432 \u0431\u0443\u0444\u0435 \u0435\u0441\u0442\u044c \u0438\u0437\u043e\u0431\u0440\u0430\u0436\u0435\u043d\u0438\u0435, Ctrl+V \u0431\u0443\u0434\u0435\u0442 \u043f\u0440\u0435\u0432\u0440\u0430\u0449\u0430\u0442\u044c\u0441\u044f \u0432 \u043d\u0430\u0441\u0442\u043e\u044f\u0449\u0443\u044e Alt+V-\u0432\u0441\u0442\u0430\u0432\u043a\u0443. \u0414\u043b\u044f \u043d\u0435\u0430\u043d\u0433\u043b\u0438\u0439\u0441\u043a\u0438\u0445 \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043e\u043a AIHelper \u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u043f\u0435\u0440\u0435\u0432\u0435\u0434\u0451\u0442 \u0442\u0435\u0440\u043c\u0438\u043d\u0430\u043b \u043d\u0430 \u0430\u043d\u0433\u043b\u0438\u0439\u0441\u043a\u0443\u044e \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0443, \u0432\u044b\u043f\u043e\u043b\u043d\u0438\u0442 \u0432\u0441\u0442\u0430\u0432\u043a\u0443 \u0438 \u0437\u0430\u0442\u0435\u043c \u0432\u0435\u0440\u043d\u0451\u0442 \u0438\u0441\u0445\u043e\u0434\u043d\u0443\u044e \u0440\u0430\u0441\u043a\u043b\u0430\u0434\u043a\u0443.\n\n\u0424\u0438\u043a\u0441 \u0440\u0430\u0431\u043e\u0442\u0430\u0435\u0442 \u0442\u043e\u043b\u044c\u043a\u043e 